create table oehr_promotions (
    promo_id   number(6, 0) generated by default on null as identity minvalue 1 maxvalue 999999 increment by 1 nocache noorder nocycle
    nokeep noscale not null enable,
    promo_name varchar2(20 byte)
);

alter table oehr_promotions
    add constraint oehr_promo_id_pk primary key ( promo_id )
        using index enable;

